//! Auto-generated by the spec-word-compliance workflow.
//!
//! Area: "Move revisions: moveFrom/moveTo paired ranges, source/dest
//! paragraphs, accept/reject pairing".
//!
//! Each `#[test]` encodes a behavioural constraint mined from
//! ECMA-376 / ISO 29500-1 §17.13.5 (revisions), §17.13.2 (cross-structure
//! annotations), MS-OI29500, and the transitional WordprocessingML schema
//! (CT_MoveBookmark / CT_MarkupRange / CT_RunTrackChange).
//!
//! A FAILING assertion here is a REAL Word-compliance gap in the stemma
//! engine, not a flaky test. Do not weaken an assertion to make it pass —
//! a fail is the finding we are hunting.
//!
//! Methodology note (consumption vs. save): stemma round-trips UNTOUCHED
//! content byte-verbatim. So `reserialize()` of an unedited document reflects
//! stemma's verbatim-preservation contract. `xmlContains/xmlOmits/xmlRegex`
//! assertions below target only markup the serializer ACTIVELY restructures
//! (Annex A child ordering, structural synthesis, validity) — never "Word
//! ignores value V on layout" (that is a read-side / oracle question).

use stemma::api::Document;

// ─── Prelude: minimal valid .docx plumbing ──────────────────────────────────

/// Build a valid minimal `.docx`. Wraps `body_xml` in
/// `<w:document …><w:body>…</w:body></w:document>` and adds the package parts
/// (`[Content_Types].xml`, `_rels/.rels`, `word/_rels/document.xml.rels`).
///
/// `extra_parts` are additional package parts as `(part_name, xml)` pairs
/// (e.g. `("word/styles.xml", "…")`); an `<Override>` content-type entry is
/// emitted for each. None of the move specs need extra parts, but the helper
/// supports them for parity with the shared spec-suite `make_test_docx`.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main" xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type override for each extra part, keyed by well-known
    // WordprocessingML part name.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (part_name, _) in extra_parts {
        let content_type = if part_name.ends_with("styles.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
        } else if part_name.ends_with("numbering.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
        } else {
            "application/xml"
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/{part_name}" ContentType="{content_type}"/>"#
        ));
    }
    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part_name, xml) in extra_parts {
            zip.start_file(*part_name, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut zip = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    use std::io::Read;
    let mut out = String::new();
    file.read_to_string(&mut out).expect("read document.xml");
    out
}

/// Parse → serialize(default) → return the re-serialized `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc
        .serialize(&stemma::ExportOptions::default())
        .expect("serialize for reserialize");
    document_xml_of(&out)
}

// ─── XML-shape helpers (no `regex` crate in this workspace) ──────────────────

/// True iff `xml` contains a start tag named `element` (e.g. `w:moveToRangeStart`)
/// whose attribute text (everything up to the closing `>`) contains every
/// fragment in `must_contain`. This translates the `<el[^>]* attr=…>` regex
/// shape into a single-tag containment check, so a match cannot straddle two
/// separate elements. The element name must match exactly (the next char after
/// the name is whitespace, `/`, or `>`), so `w:moveTo` will not match
/// `w:moveToRangeStart`.
fn tag_contains_all(xml: &str, element: &str, must_contain: &[&str]) -> bool {
    let open = format!("<{element}");
    let mut search_from = 0;
    while let Some(rel) = xml[search_from..].find(&open) {
        let start = search_from + rel;
        let Some(gt_rel) = xml[start..].find('>') else {
            return false;
        };
        let tag = &xml[start..start + gt_rel];
        let after = &xml[start + open.len()..];
        let boundary_ok = after
            .chars()
            .next()
            .map(|c| c.is_whitespace() || c == '/' || c == '>')
            .unwrap_or(false);
        if boundary_ok && must_contain.iter().all(|frag| tag.contains(frag)) {
            return true;
        }
        search_from = start + open.len();
    }
    false
}

/// True iff `xml` contains a self-closing tag `<element w:id="ID"/>` (allowing
/// `<element w:id="ID" />`) carrying the matching id and ONLY the id attribute
/// plus any of `allowed_extra` (e.g. `w:displacedByCustomXml`). Returns false
/// if any name/author/date or other unlisted `w:`-attribute appears, or if the
/// tag is not self-closing.
fn id_only_self_closing(xml: &str, element: &str, id: &str, allowed_extra: &[&str]) -> bool {
    let open = format!("<{element}");
    let mut search_from = 0;
    while let Some(rel) = xml[search_from..].find(&open) {
        let start = search_from + rel;
        let after = &xml[start + open.len()..];
        let boundary_ok = after
            .chars()
            .next()
            .map(|c| c.is_whitespace() || c == '/' || c == '>')
            .unwrap_or(false);
        let Some(gt_rel) = xml[start..].find('>') else {
            return false;
        };
        let tag = &xml[start..start + gt_rel + 1];
        search_from = start + open.len();
        if !boundary_ok {
            continue;
        }
        let id_attr = format!(r#"w:id="{id}""#);
        if !tag.contains(&id_attr) || !tag.ends_with("/>") {
            continue;
        }
        if ["w:name=", "w:author=", "w:date="]
            .iter()
            .any(|f| tag.contains(f))
        {
            continue;
        }
        // Reject any `w:`-attribute other than w:id and the allowed extras.
        // Start the scan AFTER the element name (which itself begins with `w:`),
        // i.e. at the first whitespace inside the tag.
        let mut ok = true;
        let mut idx = open.len();
        while let Some(p) = tag[idx..].find("w:") {
            let abs = idx + p;
            let rest = &tag[abs..];
            if let Some(eq) = rest.find('=') {
                let name = &rest[..eq + 1]; // includes '='
                let allowed = name == "w:id="
                    || allowed_extra.iter().any(|a| {
                        let an = if a.ends_with('=') {
                            (*a).to_string()
                        } else {
                            format!("{a}=")
                        };
                        name == an
                    });
                if !allowed {
                    ok = false;
                    break;
                }
                idx = abs + eq + 1;
            } else {
                break;
            }
        }
        if ok {
            return true;
        }
    }
    false
}

/// `<w:moveTo …>` run wrapper (NOT moveToRangeStart/End) carrying the author.
/// Distinguishes the run wrapper from the range markers by requiring a space
/// immediately after `w:moveTo` (range markers are `w:moveToRangeStart` /
/// `w:moveToRangeEnd`).
fn run_wrapper_has_author(xml: &str, element: &str, author: &str) -> bool {
    let needle = format!("<{element} ");
    let author_attr = format!(r#"w:author="{author}""#);
    let mut from = 0;
    while let Some(rel) = xml[from..].find(&needle) {
        let start = from + rel;
        let Some(gt) = xml[start..].find('>') else {
            return false;
        };
        let tag = &xml[start..start + gt];
        if tag.contains(&author_attr) {
            return true;
        }
        from = start + needle.len();
    }
    false
}

