#[test]
fn orphan_moveto_range_end_no_start_opens_lenient_runs_unaffected() {
    let body = r#"<w:p><w:r><w:t>Plain paragraph text.</w:t></w:r><w:moveToRangeEnd w:id="77"/></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "ECMA-376 §17.13.5.27, ISO 29500-1 §17.13.2: an orphan moveToRangeEnd is non-conformant but Word opens it without repair; stemma must not error on validate. Issues: {:?}",
        report.issues
    );

    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Plain paragraph text.",
        "ECMA-376 §17.13.2: a cross-structure end marker contains no content, so accepting all revisions leaves the surrounding run text unchanged."
    );
}

#[test]
fn movefrom_run_content_paragraph_pair_accept_drops_source_reject_keeps() {
    let body = r#"<w:p><w:moveFromRangeStart w:id="2" w:name="para1move" w:author="A" w:date="2021-01-01T00:00:00Z"/><w:moveFrom w:id="3" w:author="A" w:date="2021-01-01T00:00:00Z"><w:r><w:t>Relocated sentence.</w:t></w:r></w:moveFrom><w:moveFromRangeEnd w:id="2"/></w:p><w:p><w:r><w:t>Anchor sentence.</w:t></w:r></w:p><w:p><w:moveToRangeStart w:id="4" w:name="para1move" w:author="A" w:date="2021-01-01T00:00:00Z"/><w:moveTo w:id="5" w:author="A" w:date="2021-01-01T00:00:00Z"><w:r><w:t>Relocated sentence.</w:t></w:r></w:moveTo><w:moveToRangeEnd w:id="4"/></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "ECMA-376 §17.13.5.22/.25, MS-OI29500 §2.1.337: a well-formed source/destination move pair linked by matching w:name is conformant and must open without repair. Issues: {:?}",
        report.issues
    );

    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text();
    // The move is expressed across SEPARATE paragraphs, so `to_text()` joins
    // the surviving blocks with its documented block separator (a blank line).
    // The domain post-condition is the order + content (source dropped, dest
    // kept), which the block-joined form encodes faithfully.
    assert_eq!(
        accepted.trim(),
        "Anchor sentence.\n\nRelocated sentence.",
        "ECMA-376 §17.13.5.22/.25: accept drops the moveFrom source paragraph content and keeps the moveTo destination — final block order is anchor then relocated."
    );

    let rejected = Document::parse(&b)
        .expect("parse")
        .read_rejected()
        .expect("read_rejected")
        .to_text();
    assert_eq!(
        rejected.trim(),
        "Relocated sentence.\n\nAnchor sentence.",
        "ECMA-376 §17.13.5.22/.25: reject keeps the moveFrom source and drops the moveTo destination — pre-move block order is relocated then anchor."
    );
}

#[test]
fn move_range_markers_paired_by_name_id_distinct_roundtrip() {
    let body = r#"<w:p><w:moveToRangeStart w:id="0" w:author="A" w:date="2024-01-01T00:00:00Z" w:name="linkmove"/><w:moveTo w:id="1" w:author="A" w:date="2024-01-01T00:00:00Z"><w:r><w:t>Moved sentence over twenty chars.</w:t></w:r></w:moveTo><w:moveToRangeEnd w:id="0"/><w:r><w:t xml:space="preserve"> Keeper.</w:t></w:r></w:p><w:p><w:moveFromRangeStart w:id="2" w:author="A" w:date="2024-01-01T00:00:00Z" w:name="linkmove"/><w:moveFrom w:id="3" w:author="A" w:date="2024-01-01T00:00:00Z"><w:r><w:t>Moved sentence over twenty chars.</w:t></w:r></w:moveFrom><w:moveFromRangeEnd w:id="2"/></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "ECMA-376 §17.13.5.27/.23, §17.13.2, §A.1: a complete name-linked, id-paired move is conformant and must open without repair. Issues: {:?}",
        report.issues
    );

    let xml = reserialize(&b);

    // §17.13.5.27 (xmlRegex `<w:moveToRangeStart[^>]*\bw:name="linkmove"`)
    assert!(
        tag_contains_all(&xml, "w:moveToRangeStart", &[r#"w:name="linkmove""#]),
        "ECMA-376 §17.13.5.27: the move-destination container start carries the cross-structure name; the serializer must re-emit w:name on moveToRangeStart. XML: {xml}"
    );
    // §17.13.5.27 (xmlRegex `<w:moveFromRangeStart[^>]*\bw:name="linkmove"`)
    assert!(
        tag_contains_all(&xml, "w:moveFromRangeStart", &[r#"w:name="linkmove""#]),
        "ECMA-376 §17.13.5.27: source and destination are linked by the SAME name; the serializer must re-emit the identical w:name on moveFromRangeStart. XML: {xml}"
    );
    // §17.13.2 + CT_MarkupRange (xmlRegex `<w:moveToRangeEnd w:id="0"\s*/>`)
    assert!(
        id_only_self_closing(&xml, "w:moveToRangeEnd", "0", &[]),
        "ECMA-376 §17.13.2, §A.1 (CT_MarkupRange): moveToRangeEnd is paired to its start by id only and carries no name; the serializer must emit it with id=0 and without w:name. XML: {xml}"
    );
    // CT_MarkupRange (xmlOmits `<w:moveFromRangeEnd w:id="2" w:name`)
    assert!(
        !xml.contains(r#"<w:moveFromRangeEnd w:id="2" w:name"#),
        "ECMA-376 §A.1 (CT_MarkupRange): move range ends have no name attribute; the serializer must NOT copy the cross-container name onto moveFromRangeEnd. XML: {xml}"
    );
}

#[test]
fn move_run_content_requires_author_opens_clean() {
    let body = r#"<w:p><w:moveToRangeStart w:id="10" w:name="m1" w:author="Ann" w:date="2021-01-01T00:00:00Z"/><w:moveTo w:id="11" w:author="Ann" w:date="2021-01-01T00:00:00Z"><w:r><w:t>Moved sentence.</w:t></w:r></w:moveTo><w:moveToRangeEnd w:id="10"/><w:r><w:t xml:space="preserve"> Kept.</w:t></w:r><w:moveFromRangeStart w:id="12" w:name="m1" w:author="Ann" w:date="2021-01-01T00:00:00Z"/><w:moveFrom w:id="13" w:author="Ann" w:date="2021-01-01T00:00:00Z"><w:r><w:t>Moved sentence.</w:t></w:r></w:moveFrom><w:moveFromRangeEnd w:id="12"/></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "ECMA-376 §A.1 (CT_RunTrackChange/CT_TrackChange): a complete source/destination move pair whose run wrappers carry the schema-required author is well-formed and must validate without errors. Issues: {:?}",
        report.issues
    );

    let xml = reserialize(&b);
    // xmlRegex `<w:moveTo[^>]*w:author="Ann"` — the moveTo RUN wrapper (not the
    // range markers) must carry author.
    assert!(
        run_wrapper_has_author(&xml, "w:moveTo", "Ann"),
        "ECMA-376 §17.13.5.25, §A.1: author is required on the moveTo run wrapper (CT_TrackChange base) and must survive re-serialization. XML: {xml}"
    );
    // xmlRegex `<w:moveFrom[^>]*w:author="Ann"`
    assert!(
        run_wrapper_has_author(&xml, "w:moveFrom", "Ann"),
        "ECMA-376 §17.13.5.22, §A.1: author is required on the moveFrom run wrapper (CT_TrackChange base) and must survive re-serialization. XML: {xml}"
    );
}

#[test]
fn move_range_start_carries_name_author_date_movebookmark() {
    let body = r#"<w:p><w:moveFromRangeStart w:id="20" w:name="mv" w:author="Bo" w:date="2020-06-01T09:00:00Z"/><w:moveFrom w:id="21" w:author="Bo" w:date="2020-06-01T09:00:00Z"><w:r><w:t>The relocated clause.</w:t></w:r></w:moveFrom><w:moveFromRangeEnd w:id="20"/></w:p><w:p><w:moveToRangeStart w:id="22" w:name="mv" w:author="Bo" w:date="2020-06-01T09:00:00Z"/><w:moveTo w:id="23" w:author="Bo" w:date="2020-06-01T09:00:00Z"><w:r><w:t>The relocated clause.</w:t></w:r></w:moveTo><w:moveToRangeEnd w:id="22"/></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "ECMA-376 §17.13.5.24/.28, §A.1 (CT_MoveBookmark): a move pair whose range starts carry the required name+author+date is schema-valid and must validate without errors. Issues: {:?}",
        report.issues
    );

    let xml = reserialize(&b);
    // xmlRegex `<w:moveFromRangeStart[^>]*w:name="mv"[^>]*w:author="Bo"[^>]*w:date="2020-06-01T09:00:00Z"`
    assert!(
        tag_contains_all(
            &xml,
            "w:moveFromRangeStart",
            &[
                r#"w:name="mv""#,
                r#"w:author="Bo""#,
                r#"w:date="2020-06-01T09:00:00Z""#,
            ],
        ),
        "ECMA-376 §17.13.5.24, §A.1 (CT_MoveBookmark): name, author and date are required on the source range start and must round-trip on the same element. XML: {xml}"
    );
    // xmlRegex `<w:moveToRangeStart[^>]*w:name="mv"[^>]*w:author="Bo"[^>]*w:date="2020-06-01T09:00:00Z"`
    assert!(
        tag_contains_all(
            &xml,
            "w:moveToRangeStart",
            &[
                r#"w:name="mv""#,
                r#"w:author="Bo""#,
                r#"w:date="2020-06-01T09:00:00Z""#,
            ],
        ),
        "ECMA-376 §17.13.5.28, §A.1 (CT_MoveBookmark): name, author and date are required on the destination range start; the matching name links it to the source. XML: {xml}"
    );
}

