#[test]
fn orphan_complete_moveto_container_no_source_reads_as_insertion() {
    let body = r#"<w:p><w:moveToRangeStart w:id="0" w:name="orphanmove" w:author="A" w:date="2021-01-01T00:00:00Z"/><w:moveTo w:id="1" w:author="A" w:date="2021-01-01T00:00:00Z"><w:r><w:t>Moved destination text.</w:t></w:r></w:moveTo><w:moveToRangeEnd w:id="0"/><w:r><w:t xml:space="preserve"> Stationary text.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "ECMA-376 §17.13.5.28: an orphan complete destination container is non-conformant, yet Word opens it without repair; stemma must match (validate clean), not refuse. Issues: {:?}",
        report.issues
    );

    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Moved destination text. Stationary text.",
        "ECMA-376 §17.13.5.25: moveTo is an arrival/insertion; accepting all revisions keeps the moved content at the destination."
    );

    let rejected = Document::parse(&b)
        .expect("parse")
        .read_rejected()
        .expect("read_rejected")
        .to_text();
    assert_eq!(
        rejected.trim(),
        "Stationary text.",
        "ECMA-376 §17.13.5.25: rejecting the move discards the destination copy (insertion-like), leaving only the stationary run (leading space trimmed by the assertion)."
    );
}

#[test]
fn duplicate_movefrom_range_start_id_opens_lenient() {
    let body = r#"<w:p><w:moveFromRangeStart w:id="5" w:name="m1" w:author="A" w:date="2021-01-01T00:00:00Z"/><w:moveFrom w:id="6" w:author="A" w:date="2021-01-01T00:00:00Z"><w:r><w:t>First moved.</w:t></w:r></w:moveFrom><w:moveFromRangeEnd w:id="5"/></w:p><w:p><w:moveFromRangeStart w:id="5" w:name="m2" w:author="A" w:date="2021-01-01T00:00:00Z"/><w:moveFrom w:id="8" w:author="A" w:date="2021-01-01T00:00:00Z"><w:r><w:t>Second moved.</w:t></w:r></w:moveFrom><w:moveFromRangeEnd w:id="5"/></w:p><w:p><w:moveToRangeStart w:id="9" w:name="m1"/><w:moveTo w:id="10" w:author="A" w:date="2021-01-01T00:00:00Z"><w:r><w:t>First moved.</w:t></w:r></w:moveTo><w:moveToRangeEnd w:id="9"/><w:moveToRangeStart w:id="11" w:name="m2"/><w:moveTo w:id="12" w:author="A" w:date="2021-01-01T00:00:00Z"><w:r><w:t>Second moved.</w:t></w:r></w:moveTo><w:moveToRangeEnd w:id="11"/></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "ECMA-376 §17.13.5.24, ISO 29500-1 §17.13.2: duplicate moveFromRangeStart w:id is non-conformant, yet Word opens it without repair; stemma must not refuse the file. Issues: {:?}",
        report.issues
    );
}

#[test]
fn moveto_range_end_is_markuprange_id_only_never_name() {
    let body = r#"<w:p><w:moveToRangeStart w:id="44" w:name="dispmove" w:author="A" w:date="2021-01-01T00:00:00Z" w:displacedByCustomXml="next"/><w:moveTo w:id="45" w:author="A" w:date="2021-01-01T00:00:00Z"><w:r><w:t>Destination run.</w:t></w:r></w:moveTo><w:moveToRangeEnd w:id="44" w:displacedByCustomXml="prev"/></w:p><w:p><w:moveFromRangeStart w:id="46" w:name="dispmove" w:author="A" w:date="2021-01-01T00:00:00Z"/><w:moveFrom w:id="47" w:author="A" w:date="2021-01-01T00:00:00Z"><w:r><w:t>Destination run.</w:t></w:r></w:moveFrom><w:moveFromRangeEnd w:id="46"/></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "ECMA-376 §17.13.5.27/.28, §A.1: a well-formed destination container with a CT_MoveBookmark start and a CT_MarkupRange end (carrying displacedByCustomXml) is schema-valid and opens without repair. Issues: {:?}",
        report.issues
    );

    let xml = reserialize(&b);
    // xmlRegex `<w:moveToRangeStart[^>]*w:name="dispmove"[^>]*/>`
    assert!(
        tag_contains_all(&xml, "w:moveToRangeStart", &[r#"w:name="dispmove""#]),
        "ECMA-376 §17.13.5.28: the linking w:name lives on the move-destination container START and must survive re-serialization. XML: {xml}"
    );
    // xmlRegex `<w:moveToRangeEnd w:id="44"(?:\s+w:displacedByCustomXml="prev")?\s*/>`
    // CT_MarkupRange: id only, plus its own optional displacedByCustomXml; never name/author.
    assert!(
        id_only_self_closing(&xml, "w:moveToRangeEnd", "44", &["w:displacedByCustomXml"]),
        "ECMA-376 §17.13.5.27, §A.1: moveToRangeEnd is CT_MarkupRange — it re-serializes with only the matching w:id (plus its own displacedByCustomXml), never w:name or w:author. XML: {xml}"
    );
    // xmlOmits `<w:moveToRangeEnd w:id="44" w:name=`
    assert!(
        !xml.contains(r#"<w:moveToRangeEnd w:id="44" w:name="#),
        "ECMA-376 §A.1: CT_MarkupRange has no name attribute; emitting w:name on moveToRangeEnd would be schema-invalid. XML: {xml}"
    );
}

#[ignore = "open question: math moveTo accept keeps destination, but accept-all text read surfaces the math run as a single opaque-anchor placeholder (U+FFFC) instead of its text 'DEST' (left=\"\\u{fffc} tail\" right=\"DEST tail\"); destination IS preserved, the text projection diverges — read-surface question, candidate oracle item (acceptTextEquals 'DEST tail') — MS-OI29500 §2.1.341 / §17.13.5.25"]
#[test]
fn move_in_math_treated_as_ins_del_not_move() {
    let body = r#"<w:p><w:moveToRangeStart w:id="0" w:author="A" w:date="2024-01-01T00:00:00Z" w:name="m1"/><w:moveTo w:id="1" w:author="A" w:date="2024-01-01T00:00:00Z"><m:oMath><m:r><m:t>DEST</m:t></m:r></m:oMath></w:moveTo><w:moveToRangeEnd w:id="0"/><w:r><w:t xml:space="preserve"> tail</w:t></w:r></w:p><w:p><w:moveFromRangeStart w:id="2" w:author="A" w:date="2024-01-01T00:00:00Z" w:name="m1"/><w:moveFrom w:id="3" w:author="A" w:date="2024-01-01T00:00:00Z"><m:oMath><m:r><m:t>SRC</m:t></m:r></m:oMath></w:moveFrom><w:moveFromRangeEnd w:id="2"/></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = stemma::api::validate(&b);
    assert!(
        report.ok,
        "MS-OI29500 §2.1.341/.338: a well-formed math move pair (moveTo+moveFrom linked by name m1) is valid and must open without repair. Issues: {:?}",
        report.issues
    );

    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text();
    assert_eq!(
        accepted.trim(),
        "DEST tail",
        "MS-OI29500 §2.1.341 (§17.13.5.25): a math moveTo reads as an insertion, so accepting keeps the destination math run; the math moveFrom (deletion) is dropped."
    );

    let rejected = Document::parse(&b)
        .expect("parse")
        .read_rejected()
        .expect("read_rejected")
        .to_text();
    assert_eq!(
        rejected.trim(),
        "tailSRC",
        "MS-OI29500 §2.1.338 (§17.13.5.22): a math moveFrom reads as a deletion, so rejecting restores it (SRC) and removes the destination insertion (DEST)."
    );
}

#[ignore = "open question: inverted post-condition asserts !report.ok for w:moveFrom nested in w:moveFrom (Word forbids nesting), but stemma opens it leniently (ok=true, 0 issues) — confirmed Word-compliance gap (best-efforts a Word-forbidden nesting) — MS-OI29500 §2.1.338 / §17.13.5.22"]
#[test]
fn nested_movefrom_rejected_at_parse() {
    let body = r#"<w:p><w:moveFromRangeStart w:id="2" w:author="A" w:date="2024-01-01T00:00:00Z" w:name="m1"/><w:moveFrom w:id="3" w:author="A" w:date="2024-01-01T00:00:00Z"><w:moveFrom w:id="4" w:author="A" w:date="2024-01-01T00:00:00Z"><w:r><w:t>nested</w:t></w:r></w:moveFrom></w:moveFrom><w:moveFromRangeEnd w:id="2"/></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    // INVERTED post-condition: Word does not support nesting moveFrom, so a
    // Word-faithful engine must NOT report this document as opens-clean. If
    // stemma leniently accepts the nesting (report.ok == true), this assertion
    // FAILS — that failure is the smoked-out incompliance (MS-OI29500 §2.1.338).
    let report = stemma::api::validate(&b);
    assert!(
        !report.ok,
        "MS-OI29500 §2.1.338 (ECMA-376 §17.13.5.22): Word does not support nesting moveFrom; a Word-faithful engine must NOT open it clean. stemma reported ok={} (lenient accept = the incompliance). Issues: {:?}",
        report.ok, report.issues
    );
}
